    memo := make(map[int64]int64)
    var countDepth func(x int64) int64
    countDepth = func(x int64) int64 {
        if x == 1 {
            return 0
        }
        if val, ok := memo[x]; ok {
            return val
        }
        pop := int64(bits.OnesCount64(uint64(x)))
        res := countDepth(pop) + 1
        memo[x] = res
        return res
    }

    var countNumbers func(pos int, tight bool, remainingK int64) int64
    dp := make(map[[3]interface{}]int64)

    countNumbers = func(pos int, tight bool, remainingK int64) int64 {
        if remainingK < 0 {
            return 0
        }
        if pos == 0 {
            if remainingK == 0 {
                return 1
            }
            return 0
        }
        key := [3]interface{}{pos, tight, remainingK}
        if val, ok := dp[key]; ok {
            return val
        }

        maxBit := 0
        if tight {
            maxBit = int((n >> (pos - 1)) & 1)
        } else {
            maxBit = 1
        }

        res := int64(0)
        for bit := 0; bit <= maxBit; bit++ {
            newTight := tight && (bit == maxBit)
            newRemainingK := remainingK
            if bit == 1 {
                newRemainingK--
            }
            res += countNumbers(pos-1, newTight, newRemainingK)
        }
        dp[key] = res
        return res
    }

    maxBits := bits.Len64(uint64(n))
    var result int64
    for x := int64(1); x <= int64(maxBits); x++ {
        if countDepth(x) == k-1 {
            result += countNumbers(maxBits, true, x)
        }
    }
    return result
