func solve(n int64, k int64) int64 {
    if k == 0 {
        if n >= 1 {
            return 1
        }
        return 0
    }

    memo := make(map[int64]int64)
    var countDepth func(x int64) int64
    countDepth = func(x int64) int64 {
        if x == 1 {
            return 0
        }
        if val, ok := memo[x]; ok {
            return val
        }
        pop := int64(bits.OnesCount64(uint64(x)))
        depth := countDepth(pop) + 1
        memo[x] = depth
        return depth
    }

    var countNumbers func(pos int, tight bool, remainingDepth int64) int64
    dp := make(map[[3]interface{}]int64)

    s := strconv.FormatInt(n, 2)
    length := len(s)

    countNumbers = func(pos int, tight bool, remainingDepth int64) int64 {
        if pos == length {
            if remainingDepth == 0 {
                return 1
            }
            return 0
        }
        key := [3]interface{}{pos, tight, remainingDepth}
        if val, ok := dp[key]; ok {
            return val
        }

        maxDigit := 1
        if tight {
            if s[pos] == '0' {
                maxDigit = 0
            }
        }

        res := int64(0)
        for digit := 0; digit <= maxDigit; digit++ {
            newTight := tight && (digit == maxDigit)
            newRemaining := remainingDepth
            if digit == 1 {
                if remainingDepth > 0 {
                    newRemaining--
                } else {
                    continue
                }
            }
            res += countNumbers(pos+1, newTight, newRemaining)
        }
        dp[key] = res
        return res
    }

    if k == 1 {
        // Special case: numbers that reduce to 1 in one step (i.e., popcount(x) = 1)
        // So x must be a power of two, and x != 1
        var count int64
        for i := int64(1); i <= n; i <<= 1 {
            if i != 1 {
                count++
            }
        }
        return count
    }

    return countNumbers(0, true, k)
}
